/**
 * Worktree Webhook Reporter — POSTs worktree events to HQ API
 *
 * Replaces the 2 HTTP hooks (WorktreeCreate, WorktreeRemove) with command
 * hooks that handle env var interpolation at runtime.
 *
 * Fire-and-forget: always returns silent success regardless of POST outcome.
 * No-op when webhook URL or ORCHESTKIT_HOOK_TOKEN are missing.
 *
 * URL resolution: config.webhookUrl → ORCHESTKIT_HOOK_URL env var → no-op
 *
 * Hook events: WorktreeCreate, WorktreeRemove
 */

import { createHmac } from 'node:crypto';
import type { HookInput, HookResult } from '../types.js';
import { getSessionId, getCachedBranch, logHook, outputSilentSuccess } from '../lib/common.js';
import { getWebhookUrl } from '../lib/orchestration-state.js';

const HOOK_NAME = 'worktree-webhook-reporter';

interface WorktreePayload {
  event: string;
  session_id: string;
  project: string;
  timestamp: string;
  data: {
    worktree_path: string;
    branch: string;
  };
}

function getProjectSlug(): string {
  const dir = process.env.CLAUDE_PROJECT_DIR || process.cwd();
  return dir.split('/').pop() || 'unknown';
}

function signPayload(body: string, secret: string): string {
  const mac = createHmac('sha256', secret).update(body).digest('hex');
  return `sha256=${mac}`;
}

function buildPayload(input: HookInput): WorktreePayload {
  const sessionId = input.session_id || getSessionId();
  const worktreePath = input.tool_input?.file_path || input.tool_input?.path || 'unknown';

  return {
    event: input.hook_event || 'WorktreeCreate',
    session_id: sessionId,
    project: getProjectSlug(),
    timestamp: new Date().toISOString(),
    data: {
      worktree_path: String(worktreePath),
      branch: getCachedBranch(),
    },
  };
}

async function postPayload(payload: WorktreePayload, hookUrl: string, hookToken: string): Promise<void> {
  const body = JSON.stringify(payload);
  const signature = signPayload(body, hookToken);
  const url = `${hookUrl.replace(/\/$/, '')}/worktree`;

  logHook(HOOK_NAME, `POSTing ${payload.event} to ${url}`);

  const response = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'X-CC-Hooks-Signature': signature },
    body,
    signal: AbortSignal.timeout(4000),
  });

  logHook(HOOK_NAME, `POST complete: ${response.status}`);
}

/**
 * Build WorktreePayload and POST to the HQ API worktree endpoint.
 */
export async function worktreeWebhookReporter(input: HookInput): Promise<HookResult> {
  const hookUrl = getWebhookUrl();
  const hookToken = process.env.ORCHESTKIT_HOOK_TOKEN;

  if (!hookUrl || !hookToken) {
    logHook(HOOK_NAME, 'No webhookUrl/TOKEN configured, skipping');
    return outputSilentSuccess();
  }

  try {
    await postPayload(buildPayload(input), hookUrl, hookToken);
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    logHook(HOOK_NAME, `POST failed (non-blocking): ${msg}`, 'warn');
  }

  return outputSilentSuccess();
}
